content.text:
sum by (error_type) (
  count_over_time(
    {service="genai-completion", env="prod"}
      | json
      | event="request.error"
    [15m]
  )
)

sum by (feature_name) (
  sum_over_time(
    {service="genai-completion", env="prod"}
      | json
      | event="request.complete"
      | unwrap total_cost_usd
    [24h]
  )
)
